(13, 1, '2025-05-14 10:09:20', '2025-05-14 08:09:20', 'Thanks for registering!\n\nTo complete the activation of your account, go to the following link and click on the <strong>Activate</strong> button:\n<a href=\"{{{activate.url}}}\">{{{activate.url}}}</a>\n\nIf the \'Activation Key\' field is empty, copy and paste the following into the field - {{key}}', '[{{{site.name}}}] Activate your account', 'Thanks for registering!\n\nTo complete the activation of your account, go to the following link and click on the \'Activate\' button: {{{activate.url}}}\n\nIf the \'Activation Key\' field is empty, copy and paste the following into the field - {{key}}', 'publish', 'closed', 'closed', '', 'site-name-activate-your-account', '', '', '2025-05-14 10:09:20', '2025-05-14 08:09:20', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=13', 0, 'bp-email', '', 0),
(14, 1, '2025-05-14 10:09:20', '2025-05-14 08:09:20', '<a href=\"{{{initiator.url}}}\">{{initiator.name}}</a> wants to add you as a friend.\n\nTo accept this request and manage all of your pending requests, visit: <a href=\"{{{friend-requests.url}}}\">{{{friend-requests.url}}}</a>', '[{{{site.name}}}] New friendship request from {{initiator.name}}', '{{initiator.name}} wants to add you as a friend.\n\nTo accept this request and manage all of your pending requests, visit: {{{friend-requests.url}}}\n\nTo view {{initiator.name}}\'s profile, visit: {{{initiator.url}}}', 'publish', 'closed', 'closed', '', 'site-name-new-friendship-request-from-initiator-name', '', '', '2025-05-14 10:09:20', '2025-05-14 08:09:20', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=14', 0, 'bp-email', '', 0),
(15, 1, '2025-05-14 10:09:21', '2025-05-14 08:09:21', '<a href=\"{{{friendship.url}}}\">{{friend.name}}</a> accepted your friend request.', '[{{{site.name}}}] {{friend.name}} accepted your friendship request', '{{friend.name}} accepted your friend request.\n\nTo learn more about them, visit their profile: {{{friendship.url}}}', 'publish', 'closed', 'closed', '', 'site-name-friend-name-accepted-your-friendship-request', '', '', '2025-05-14 10:09:21', '2025-05-14 08:09:21', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=15', 0, 'bp-email', '', 0),
(16, 1, '2025-05-14 10:09:21', '2025-05-14 08:09:21', 'Group details for the group &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot; were updated:\n<blockquote>{{changed_text}}</blockquote>', '[{{{site.name}}}] Group details updated', 'Group details for the group \"{{group.name}}\" were updated:\n\n{{changed_text}}\n\nTo view the group, visit: {{{group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-group-details-updated', '', '', '2025-05-14 10:09:21', '2025-05-14 08:09:21', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=16', 0, 'bp-email', '', 0),
(17, 1, '2025-05-14 10:09:21', '2025-05-14 08:09:21', '<a href=\"{{{inviter.url}}}\">{{inviter.name}}</a> has invited you to join the group: &quot;{{group.name}}&quot;.\n\n{{invite.message}}\n\n<a href=\"{{{invites.url}}}\">Go here to accept your invitation</a> or <a href=\"{{{group.url}}}\">visit the group</a> to learn more.', '[{{{site.name}}}] You have an invitation to the group: \"{{group.name}}\"', '{{inviter.name}} has invited you to join the group: \"{{group.name}}\".\n\n{{invite.message}}\n\nTo accept your invitation, visit: {{{invites.url}}}\n\nTo learn more about the group, visit: {{{group.url}}}.\nTo view {{inviter.name}}\'s profile, visit: {{{inviter.url}}}', 'publish', 'closed', 'closed', '', 'site-name-you-have-an-invitation-to-the-group-group-name', '', '', '2025-05-14 10:09:21', '2025-05-14 08:09:21', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=17', 0, 'bp-email', '', 0),
(18, 1, '2025-05-14 10:09:21', '2025-05-14 08:09:21', 'You have been promoted to <b>{{promoted_to}}</b> in the group &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot;.', '[{{{site.name}}}] You have been promoted in the group: \"{{group.name}}\"', 'You have been promoted to {{promoted_to}} in the group: \"{{group.name}}\".\n\nTo visit the group, go to: {{{group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-you-have-been-promoted-in-the-group-group-name', '', '', '2025-05-14 10:09:21', '2025-05-14 08:09:21', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=18', 0, 'bp-email', '', 0),
(19, 1, '2025-05-14 10:09:21', '2025-05-14 08:09:21', '<a href=\"{{{profile.url}}}\">{{requesting-user.name}}</a> wants to join the group &quot;{{group.name}}&quot;.\n {{request.message}}\n As you are an administrator of this group, you must either accept or reject the membership request.\n\n<a href=\"{{{group-requests.url}}}\">Go here to manage this</a> and all other pending requests.', '[{{{site.name}}}] Membership request for group: {{group.name}}', '{{requesting-user.name}} wants to join the group \"{{group.name}}\". As you are the administrator of this group, you must either accept or reject the membership request.\n\nTo manage this and all other pending requests, visit: {{{group-requests.url}}}\n\nTo view {{requesting-user.name}}\'s profile, visit: {{{profile.url}}}', 'publish', 'closed', 'closed', '', 'site-name-membership-request-for-group-group-name', '', '', '2025-05-14 10:09:21', '2025-05-14 08:09:21', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=19', 0, 'bp-email', '', 0),
(20, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', '{{sender.name}} sent you a new message: &quot;{{usersubject}}&quot;\n\n<blockquote>&quot;{{usermessage}}&quot;</blockquote>\n\n<a href=\"{{{message.url}}}\">Go to the discussion</a> to reply or catch up on the conversation.', '[{{{site.name}}}] New message from {{sender.name}}', '{{sender.name}} sent you a new message: \"{{usersubject}}\"\n\n\"{{usermessage}}\"\n\nGo to the discussion to reply or catch up on the conversation: {{{message.url}}}', 'publish', 'closed', 'closed', '', 'site-name-new-message-from-sender-name', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=20', 0, 'bp-email', '', 0),
(21, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', 'You recently changed the email address associated with your account on {{site.name}} to {{user.email}}. If this is correct, <a href=\"{{{verify.url}}}\">go here to confirm the change</a>.\n\nOtherwise, you can safely ignore and delete this email if you have changed your mind, or if you think you have received this email in error.', '[{{{site.name}}}] Verify your new email address', 'You recently changed the email address associated with your account on {{site.name}} to {{user.email}}. If this is correct, go to the following link to confirm the change: {{{verify.url}}}\n\nOtherwise, you can safely ignore and delete this email if you have changed your mind, or if you think you have received this email in error.', 'publish', 'closed', 'closed', '', 'site-name-verify-your-new-email-address', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=21', 0, 'bp-email', '', 0),
(22, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', 'Your membership request for the group &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot; has been accepted.', '[{{{site.name}}}] Membership request for group \"{{group.name}}\" accepted', 'Your membership request for the group \"{{group.name}}\" has been accepted.\n\nTo view the group, visit: {{{group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-membership-request-for-group-group-name-accepted', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=22', 0, 'bp-email', '', 0),
(23, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', 'Your membership request for the group &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot; has been rejected.', '[{{{site.name}}}] Membership request for group \"{{group.name}}\" rejected', 'Your membership request for the group \"{{group.name}}\" has been rejected.\n\nTo request membership again, visit: {{{group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-membership-request-for-group-group-name-rejected', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=23', 0, 'bp-email', '', 0),
(24, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', 'An administrator accepted an invitation to join &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot; on your behalf.\n\nIf you disagree with this, you can leave the group at anytime visiting your <a href=\"{{{leave-group.url}}}\">groups memberships page</a>.', '[{{{site.name}}}] Membership request for group \"{{group.name}}\" accepted', 'An administrator accepted an invitation to join \"{{group.name}}\" on your behalf.\n\nIf you disagree with this, you can leave the group at anytime visiting your groups memberships page: {{{leave-group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-membership-request-for-group-group-name-accepted-2', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=24', 0, 'bp-email', '', 0),
(25, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', 'An administrator rejected an invitation to join &quot;<a href=\"{{{group.url}}}\">{{group.name}}</a>&quot; on your behalf.\n\nIf you disagree with this, please contact the site administrator.', '[{{{site.name}}}] Membership request for group \"{{group.name}}\" rejected', 'An administrator rejected an invitation to join \"{{group.name}}\" on your behalf.\n\nIf you disagree with this, please contact the site administrator.', 'publish', 'closed', 'closed', '', 'site-name-membership-request-for-group-group-name-rejected-2', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=25', 0, 'bp-email', '', 0),
(26, 1, '2025-05-14 10:09:22', '2025-05-14 08:09:22', '<a href=\"{{{inviter.url}}}\">{{inviter.name}}</a> has invited you to join the site: &quot;{{site.name}}&quot;.\n\n{{usermessage}}\n\n<a href=\"{{{invite.accept_url}}}\">Accept your invitation</a> or <a href=\"{{{site.url}}}\">visit the site</a> to learn more.', '{{inviter.name}} has invited you to join {{site.name}}', '{{inviter.name}} has invited you to join the site \"{{site.name}}\".\n\n{{usermessage}}\n\nTo accept your invitation, visit: {{{invite.accept_url}}}\n\nTo learn more about the site, visit: {{{site.url}}}.\nTo view {{inviter.name}}\'s profile, visit: {{{inviter.url}}}', 'publish', 'closed', 'closed', '', 'inviter-name-has-invited-you-to-join-site-name', '', '', '2025-05-14 10:09:22', '2025-05-14 08:09:22', '', 0, 'http://localhost/WebArtAI-wordpress/?post_type=bp-email&p=26', 0, 'bp-email', '', 0),
